import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const apiKey = process.env.PLATFORM_API_KEY;
  const baseUrl = process.env.APP_BASE_URL;
  if (!apiKey || !baseUrl) { console.error('PLATFORM_API_KEY or APP_BASE_URL missing'); process.exit(1); }
  const namespaces = ['mediforce', 'appsilon'];
  const seen = new Map();
  for (const ns of namespaces) {
    try {
      const res = await fetch(`${baseUrl}/api/users/members?handle=${encodeURIComponent(ns)}`, {
        headers: { 'X-Api-Key': apiKey, Accept: 'application/json' },
      });
      if (!res.ok) { console.error(`Failed to fetch members from ${ns}: ${res.status}`); continue; }
      const data = await res.json();
      for (const m of (data.members || [])) {
        if (!seen.has(m.uid)) {
          seen.set(m.uid, { id: m.uid, label: m.displayName || m.email || m.uid, email: m.email || '', role: m.role || 'member', avatarUrl: m.avatarUrl || '' });
        }
      }
    } catch (err) { console.error(`Error fetching ${ns}: ${err?.message || err}`); }
  }
  const options = [...seen.values()];
  writeFileSync('/output/result.json', JSON.stringify({ options }));
  console.log(`Fetched ${options.length} unique member(s) from ${namespaces.join(', ')}`);
} catch (err) {
  console.error('fetch_members crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
const DEFAULT_QUESTION = 'Before looking at categories — what is your first gut feeling?

**0. What frustrates you most or what do you need most in Mediforce right now?**

Now, per category:

**A. Product** — Which features are most critical for this sprint? What customer development conversations should we prioritize? What are we doing to validate the product with the market?

**B. UX** — What needs improvement from the user's perspective?

**C. Workflow** — Which workflows do our users need most? What is not ideal in existing workflows? Are there workflows we know clients want that we should prioritize?

**D. Engine** — What is missing in the platform's expressiveness? What should we change in the workflow execution engine?

**E. Tech-debt** — What needs cleanup before it grows into a real problem?

**F. Infra / Security** — What is important? What is urgent?

**G. Bug** — Which known bugs are most painful?

Rate priorities where possible: 🔴 critical, 🟠 important, 🟡 nice-to-have. A couple of sentences per category is fine, but feel free to go deeper where it matters.';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const rows = input.steps?.select_members?.rows || [];
  const fetchedMembers = input.steps?.fetch_members?.options || [];
  const includedIds = new Set(rows.filter(r => r.values?.include === 'yes').map(r => r.itemId));
  const teamMembers = fetchedMembers.filter(m => includedIds.has(m.id)).map(m => ({ userId: m.id, email: m.email }));
  if (teamMembers.length === 0) { console.error('No members selected'); process.exit(1); }
  const hours = Number(input.durationHours);
  if (!Number.isFinite(hours) || hours <= 0) { console.error('durationHours must be a positive number'); process.exit(1); }
  const deadline = new Date(Date.now() + hours * 3600000).toISOString();
  const question = input.question || DEFAULT_QUESTION;
  writeFileSync('/output/result.json', JSON.stringify({ teamMembers, question, deadline }));
  console.log(`Selected ${teamMembers.length} member(s), deadline: ${deadline}`);
} catch (err) {
  console.error('prepare crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';
try {
  const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
  const spawned = input.steps?.spawn_perspectives?.spawned || [];
  const apiKey = process.env.PLATFORM_API_KEY;
  const baseUrl = process.env.APP_BASE_URL;
  if (!apiKey || !baseUrl) { console.error('PLATFORM_API_KEY or APP_BASE_URL missing'); process.exit(1); }
  const responses = [];
  for (const entry of spawned) {
    const instanceId = entry.instanceId;
    try {
      const res = await fetch(`${baseUrl}/api/processes/${instanceId}`, {
        headers: { 'X-Api-Key': apiKey, Accept: 'application/json' },
      });
      if (!res.ok) { console.error(`Failed to fetch instance ${instanceId}: ${res.status}`); continue; }
      const instance = await res.json();
      const stepOutput = instance.variables?.provide_perspective;
      const perspective = stepOutput?.paramValues?.perspective ?? stepOutput;
      responses.push({ instanceId, perspective: perspective || null });
    } catch (err) {
      console.error(`Error fetching instance ${instanceId}: ${err?.message || err}`);
    }
  }
  const summary = `Collected ${responses.length} of ${spawned.length} responses`;
  console.log(summary);
  writeFileSync('/output/result.json', JSON.stringify({
    responses,
    responseCount: responses.length,
    totalSpawned: spawned.length,
    summary
  }));
} catch (err) {
  console.error('collect_responses crashed:', err?.stack || err?.message || String(err));
  process.exit(1);
}
